html:
{%- set qr_b64 = get_qr_base64(doc.name) -%}
<style>
  @page { size: 80mm 50mm; margin: 0; }
  body, .print-format { margin: 0 !important; padding: 0 !important; background: #fff; }
  .batch-label {
    box-sizing: border-box;
    width: 80mm;
    height: 50mm;
    padding: 2mm;
    font-family: sans-serif;
    display: flex;
    align-items: center;
    gap: 3mm;
    overflow: hidden;
  }
  .qr-block {
    flex-shrink: 0;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 1mm;
  }
  .qr-block img { width: 28mm; height: 28mm; }
  .qr-label {
    font-size: 6pt;
    text-align: center;
    word-break: break-all;
    max-width: 28mm;
  }
  .info {
    display: flex;
    flex-direction: column;
    justify-content: center;
    gap: 1.5mm;
    overflow: hidden;
    padding-top: 1mm;
  }
  .item-name {
    font-size: 9pt;
    font-weight: bold;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
  }
  .info table { font-size: 8pt; border-collapse: collapse; }
  .info td { padding: 0.5mm 0; vertical-align: top; }
  .lbl { color: #555; padding-right: 4mm; }
</style>
<div class="batch-label">
  <div class="qr-block">
    <img src="data:image/png;base64,{{ qr_b64 }}" alt="{{ doc.name }}">
    <div class="qr-label">{{ doc.name }}</div>
  </div>
  <div class="info">
    <div class="item-name">{{ doc.item_name or doc.item }}</div>
    <table>
      <tr>
        <td class="lbl">Produced:</td>
        <td>{{ frappe.format_date(doc.manufacturing_date or doc.creation, 'yyyy-MM-dd') }}</td>
      </tr>
      {%- if doc.expiry_date %}
      <tr>
        <td class="lbl">Expires:</td>
        <td>{{ frappe.format_date(doc.expiry_date, 'yyyy-MM-dd') }}</td>
      </tr>
      {%- endif %}
    </table>
  </div>
</div>
